    principals {
      type        = "Service"
      identifiers = ["cloudfront.amazonaws.com"]
    }

    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.origin.arn}/*"]

    condition {
      test     = "StringEquals"
      variable = "AWS:SourceArn"
      values   = [aws_cloudfront_distribution.listell.arn]
    }
  }
}

resource "aws_s3_bucket_policy" "origin" {
  # Reference public access block to create implicit dependency — policy must be
  # applied after the block is in place
  bucket = aws_s3_bucket_public_access_block.origin.bucket
  policy = data.aws_iam_policy_document.origin_oac.json
}

resource "aws_s3_object" "index" {
  bucket       = aws_s3_bucket.origin.id
  key          = "index.html"
  content_type = "text/html"
  source       = "${path.module}/files/index.html"
  source_hash  = filemd5("${path.module}/files/index.html")
}

data "aws_cloudfront_cache_policy" "caching_optimized" {
  name = "Managed-CachingOptimized"
}

resource "aws_cloudfront_origin_access_control" "listell" {
  name                              = "listell-co-uk-oac"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

resource "aws_cloudfront_distribution" "listell" {
  #checkov:skip=CKV_AWS_86: Access logging not required for a static holding page
  #checkov:skip=CKV2_AWS_47: WAF not required for a static holding page

  aliases             = [local.domain_name, local.www_domain_name]
  default_root_object = "index.html"
  enabled             = true
  http_version        = "http2and3"
  is_ipv6_enabled     = true
  price_class         = "PriceClass_100"

  origin {
    domain_name              = aws_s3_bucket.origin.bucket_regional_domain_name
    origin_id                = aws_s3_bucket.origin.id
    origin_access_control_id = aws_cloudfront_origin_access_control.listell.id
  }

  default_cache_behavior {
    allowed_methods        = ["GET", "HEAD"]
    cached_methods         = ["GET", "HEAD"]
    target_origin_id       = aws_s3_bucket.origin.id
    viewer_protocol_policy = "redirect-to-https"
    cache_policy_id        = data.aws_cloudfront_cache_policy.caching_optimized.id
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    acm_certificate_arn      = aws_acm_certificate_validation.listell.certificate_arn
    ssl_support_method       = "sni-only"
    minimum_protocol_version = "TLSv1.2_2021"
  }

  tags = {
    Name      = "listell-co-uk"
    ManagedBy = "Terraform"
  }
}

resource "aws_acm_certificate" "listell" {
  provider = aws.us_east_1

  domain_name               = local.domain_name
  validation_method         = "DNS"
  subject_alternative_names = [local.www_domain_name]

  lifecycle {
    create_before_destroy = true
  }

  tags = {
    Name      = local.domain_name
    ManagedBy = "Terraform"
  }
}

resource "aws_acm_certificate_validation" "listell" {
  provider = aws.us_east_1

  certificate_arn         = aws_acm_certificate.listell.arn
  validation_record_fqdns = [for record in aws_route53_record.acm_validation : record.fqdn]
}

